from adapter import heuristic_min_trade_sample_for_bias  # noqa: E402,F401


class TestMinTradeSampleForBias(unittest.TestCase):
    def test_flags_short_bias_low_sample(self):
        stats = {"side_bias": "short", "trades_lifetime": 1}
        fired, reason = heuristic_min_trade_sample_for_bias(stats)
        self.assertTrue(fired)
        self.assertIn("short", reason)
        self.assertIn("1 lifetime", reason)

    def test_no_flag_when_sufficient_trades(self):
        stats = {"side_bias": "long", "trades_lifetime": 5}
        fired, _ = heuristic_min_trade_sample_for_bias(stats)
        self.assertFalse(fired)

    def test_no_flag_when_bias_is_null(self):
        stats = {"side_bias": None, "trades_lifetime": 1}
        fired, _ = heuristic_min_trade_sample_for_bias(stats)
        self.assertFalse(fired)

    def test_no_flag_when_bias_key_missing(self):
        stats = {"trades_lifetime": 3}
        fired, _ = heuristic_min_trade_sample_for_bias(stats)
        self.assertFalse(fired)

    def test_no_flag_when_empty_stats(self):
        fired, _ = heuristic_min_trade_sample_for_bias({})
        self.assertFalse(fired)
